import React from 'react';

function Achievements({ data }) {
  if (!data) return null;

  return (
    <section id="achievements" className="py-16 bg-gray-50">
      <div className="max-w-6xl mx-auto px-4">
        <h2 className="text-4xl font-bold text-gray-800 mb-12 text-center">Achievements</h2>
        <div className="grid md:grid-cols-3 gap-6">
          {data.map((achievement) => (
            <div key={achievement.id} className="bg-white rounded-lg shadow-lg p-6 hover:shadow-xl transition transform hover:-translate-y-1">
              <div className="flex items-center gap-3 mb-4">
                <div className="text-3xl">🏆</div>
              </div>
              <h3 className="text-lg font-semibold text-gray-800 mb-2">{achievement.title}</h3>
              <p className="text-blue-600 font-semibold">{achievement.year}</p>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

export default Achievements;
